                    if (cur < dist[j]) {
                        dist[j] = cur;
                        prevJob[j] = j0;
                    }
                    if (dist[j] < delta) {
                        delta = dist[j];
                        j1 = j;
                    }
                }
            }

            for (int j = 0; j <= n; j++) {
                if (used[j]) {
                    u[matchJob[j]] += delta;
                    v[j] -= delta;
                } else {
                    dist[j] -= delta;
                }
            }

            j0 = j1;
            if (matchJob[j0] == 0) break;
        }

        while (j0 != 0) {
            matchJob[j0] = matchJob[prevJob[j0]];
            j0 = prevJob[j0];
        }
    }

    vector<int> assignment(n);
